using System.Text.Json;
using DotLLM.Cpu.Kernels;
using Xunit;
using Xunit.Abstractions;

namespace DotLLM.Tests.Integration.Engine;

/// <summary>
/// Cross-reference Mamba-3 kernels against the <c>VikramKarLex/mamba3-minimal</c>
/// PyTorch reference. Fixtures generated by
/// <c>tests/DotLLM.Tests.Integration/Fixtures/Mamba3/capture_fixtures.py</c> —
/// regenerate if the kernel contract or reference version changes.
/// </summary>
public class Mamba3ReferenceCompareTests
{
    private const float AbsTol = 1e-5f;
    private const float RelTol = 1e-4f;

    private readonly ITestOutputHelper _output;

    public Mamba3ReferenceCompareTests(ITestOutputHelper output) => _output = output;

    private static string FixturePath() =>
        Path.Combine(AppContext.BaseDirectory, "Fixtures", "Mamba3", "fixture.json");

    private static Fixture LoadFixture()
    {
        string path = FixturePath();
        string fullPath = Path.GetFullPath(path);
        if (!File.Exists(fullPath))
            throw new FileNotFoundException($"Mamba-3 fixture not found at {fullPath}. Run capture_fixtures.py first.");
        using var stream = File.OpenRead(fullPath);
        var f = JsonSerializer.Deserialize<Fixture>(stream, new JsonSerializerOptions
        {
            PropertyNamingPolicy = JsonNamingPolicy.SnakeCaseLower,
        }) ?? throw new InvalidDataException("Fixture deserialised to null.");
        return f;
    }

    [SkippableFact]
    public void Discretize_MatchesReference()
    {
        Skip.IfNot(File.Exists(Path.GetFullPath(FixturePath())),
            "fixture.json missing — run tests/DotLLM.Tests.Integration/Fixtures/Mamba3/capture_fixtures.py");

        var f = LoadFixture();
        int batch = f.Config["batch"].GetInt32();
        int seqlen = f.Config["seqlen"].GetInt32();
        int nheads = f.Config["nheads"].GetInt32();
        Assert.Equal(1, batch);

        // Inputs (already post-softplus / post-sigmoid per capture script).
        float[] dt = f.Activated["dt"].Data;         // [b, l, h] flat
        float[] lam = f.Activated["lam"].Data;
        float[] a = f.Inputs["A"].Data;              // [h]

        // Expected from reference
        float[] expAlpha = f.Expected["alpha"].Data;
        float[] expBeta = f.Expected["beta"].Data;
        float[] expGamma = f.Expected["gamma"].Data;

        // Run our kernel
        int totalTokens = seqlen;  // batch=1
        float[] alpha = new float[totalTokens * nheads];
        float[] beta = new float[totalTokens * nheads];
        float[] gamma = new float[totalTokens * nheads];

        Mamba3Discretize.Execute(dt, a, lam, alpha, beta, gamma, seqlen, nheads);

        _output.WriteLine($"dt: [{string.Join(", ", dt.Take(4).Select(v => v.ToString("F4")))}, ...]");
        _output.WriteLine($"alpha expected[0..4]: [{string.Join(", ", expAlpha.Take(4).Select(v => v.ToString("F6")))}]");
        _output.WriteLine($"alpha ours[0..4]:     [{string.Join(", ", alpha.Take(4).Select(v => v.ToString("F6")))}]");

        AssertCloseElementwise("alpha", expAlpha, alpha);
        AssertCloseElementwise("beta", expBeta, beta);
        AssertCloseElementwise("gamma", expGamma, gamma);
    }

    private static void AssertCloseElementwise(string label, float[] expected, float[] actual)
    {
        Assert.Equal(expected.Length, actual.Length);
        for (int i = 0; i < expected.Length; i++)
        {
            float e = expected[i];
            float a = actual[i];
            float absDiff = MathF.Abs(e - a);
            float relDiff = absDiff / (MathF.Abs(e) + 1e-12f);
            if (absDiff > AbsTol && relDiff > RelTol)
            {
                Assert.Fail($"{label}[{i}]: expected={e:F8} actual={a:F8} absDiff={absDiff:E3} relDiff={relDiff:E3} "
                            + $"(tolerance abs={AbsTol:E0} rel={RelTol:E0})");
            }
        }
    }

    // ── Fixture DTOs ──────────────────────────────────────────────────────────

    private sealed class Fixture
    {
        public Dictionary<string, JsonElement> Config { get; set; } = default!;
        public Dictionary<string, Tensor> Inputs { get; set; } = default!;
        public Dictionary<string, Tensor> Activated { get; set; } = default!;
        public Dictionary<string, Tensor> Expected { get; set; } = default!;
    }

    private sealed class Tensor
    {
        public int[] Shape { get; set; } = [];
        public float[] Data { get; set; } = [];
    }
}
